// ============================================================
// SCHRITT: Metadaten auslesen + Kontakte mappen
// ============================================================
// Leadtyp + Listen-ID kommen aus dem Upload-Formular.
// Alle Excel-Zeilen sind Kontaktdaten (keine Metadaten-Zeilen).
// ============================================================

const allItems = items.map(i => i.json);

// --- Metadaten aus Formular ---
const leadtypValue = $('Upload Formular').first().json['Leadtyp'] || 'Unternehmerboard';
const listId = $('Upload Formular').first().json['HubSpot Listen-ID'] || '';

// --- Segmentname (optional, aus erster Zeile wenn vorhanden) ---
const segmentnameValue = '';

// --- Alle Zeilen sind Kontaktdaten ---
const contactRows = allItems;

// branchen: HubSpot akzeptiert nur diese Werte (inkl. Tippfehler "Elektrontechnik")
const VALID_BRANCHEN = ['Werbung/Design','Coaching','Personal','Health','Logistik','B2B Services','Handwerk','Elektrontechnik','Immobilien','Maschinenbau','Handel','Chemie','Consulting','Bau','Architektur-Design','Software','Produktion'];
const BRANCHEN_ALIASES = {
  'elektrotechnik':   'Elektrontechnik',
  'elektro':          'Elektrontechnik',
  'it':               'Software',
  'informatik':       'Software',
  'architektur':      'Architektur-Design',
  'werbung':          'Werbung/Design',
  'design':           'Werbung/Design',
  'hr':               'Personal',
  'gesundheit':       'Health',
  'transport':        'Logistik',
  'dienstleistungen': 'B2B Services',
};
function mapBranchen(raw) {
  const v = (raw || '').toString().trim();
  if (!v) return '';
  if (VALID_BRANCHEN.includes(v)) return v;
  const lower = v.toLowerCase();
  const ciMatch = VALID_BRANCHEN.find(b => b.toLowerCase() === lower);
  if (ciMatch) return ciMatch;
  return BRANCHEN_ALIASES[lower] || '';
}

// numemployees: HubSpot akzeptiert nur diese Werte
const VALID_EMPLOYEES = ['1-5','5-25','25-50','50-100','100-500','500-1000','1000+'];
function mapNumEmployees(raw) {
  const v = (raw || '').toString().trim();
  if (!v) return '';
  if (VALID_EMPLOYEES.includes(v)) return v;
  const match = v.match(/(\d+)/);
  if (!match) return '';
  const n = parseInt(match[1], 10);
  if (n <= 5)   return '1-5';
  if (n <= 25)  return '5-25';
  if (n <= 50)  return '25-50';
  if (n <= 100) return '50-100';
  if (n <= 500) return '100-500';
  if (n <= 1000) return '500-1000';
  return '1000+';
}

const result = [];

for (const row of contactRows) {
  // Nur Zeilen mit gültiger E-Mail verarbeiten
  const email = (row['email'] || '').toString().trim();
  if (!email) continue;

  // Telefonnummer bereinigen: führendes ' entfernen (Excel-Artefakt)
  let phone = (row['phone'] || '').toString().trim();
  if (phone.startsWith("'")) phone = phone.slice(1);

  const branchenVal     = mapBranchen(row['industry']);
  const numemployeesVal = mapNumEmployees(row['companySize']);

  const mapped = {
    // ── HubSpot Standard-Felder ──────────────────────────────
    email:           email,
    firstname:       (row['firstName'] || '').toString().trim(),
    lastname:        (row['lastName']  || '').toString().trim(),
    phone:           phone,
    hs_linkedin_url: (row['linkedinUrl']   || '').toString().trim(),
    jobtitle:        (row['jobTitle']      || '').toString().trim(),
    company:         (row['companyName']    || '').toString().trim(),
    website:         (row['companyWebsite'] || row['companyDomain'] || '').toString().trim(),
    // ── Custom-Property ─────────────────────────────────────
    leadtyp:         leadtypValue,
    // ── Interne Felder für Rückschreiben der HubSpot-ID ──────
    _segmentname:    segmentnameValue,
    _source_id:      (row['_id'] || '').toString().trim(),
    _listId:         listId,
  };
  // Enum-Felder nur setzen wenn gemappt (leerer Wert → HubSpot-Validierungsfehler)
  if (branchenVal)     mapped.branchen     = branchenVal;
  if (numemployeesVal) mapped.numemployees = numemployeesVal;

  result.push({ json: mapped });
}

return result;

// ============================================================
// HubSpot IDs als CSV ausgeben (für Rückschreiben in Spalte DE)
// ============================================================
// Gibt eine CSV-Datei aus mit: email, hubspotId
// Diese kann genutzt werden, um manuell oder per VLOOKUP
// die IDs in die Originaldatei (Spalte DE / hubspotId) einzutragen.
// ============================================================

const allData = items[0].json.data;

if (!Array.isArray(allData)) {
  return [{ json: { info: 'Keine Daten zum Exportieren' } }];
}

let csvLines = ['email,hubspotId'];

for (const row of allData) {
  const email = (row.email || '').replace(/,/g, '');
  const hsId  = (row.id    || '').toString();
  csvLines.push(`${email},${hsId}`);
}

return [{
  json: {
    totalImported: csvLines.length - 1,
    message: `${csvLines.length - 1} Kontakte erfolgreich importiert`,
  },
  binary: {
    data: {
      data: Buffer.from(csvLines.join('\n')).toString('base64'),
      mimeType: 'text/csv',
      fileExtension: 'csv',
      fileName: 'hubspot_ids_rueckschreiben.csv',
    }
  }
}];
